function FanBacks({count,orientation}){
  const n=Math.min(count||0,13); if(!n) return <div style={{width:orientation==="top"?140:60,height:orientation==="top"?80:140}}/>;
  if(orientation==="top"){
    const spread=Math.min(26,220/n),totalW=spread*(n-1)+54;
    return(
      <div style={{position:"relative",width:Math.max(140,totalW),height:88,flexShrink:0}}>
        {Array.from({length:n}).map((_,i)=>{const pct2=n===1?.5:i/(n-1),rot=(pct2-.5)*22,x=(pct2-.5)*(spread*(n-1)),yUp=Math.abs(rot)*.6;
          return <div key={i} style={{position:"absolute",left:`calc(50% + ${x}px - 27px)`,bottom:`${yUp}px`,transform:`rotate(${rot}deg)`,transformOrigin:"bottom center",zIndex:i}}><CardBack small/></div>;})}
      </div>
    );
  }
  const spread=Math.min(20,160/n),totalH=spread*(n-1)+78,rot=orientation==="left"?-90:90;
  return(
    <div style={{position:"relative",height:Math.max(110,totalH),width:60,flexShrink:0}}>
      {Array.from({length:n}).map((_,i)=>{const y=(n===1?.5:i/(n-1))*(spread*(n-1));
        return <div key={i} style={{position:"absolute",top:`${y}px`,left:"50%",transform:`translateX(-50%) rotate(${rot}deg)`,zIndex:i}}><CardBack small/></div>;})}
    </div>
  );
}

